create extension if not exists pgcrypto;
create table public.profiles (id uuid primary key references auth.users(id) on delete cascade, full_name text, email text, avatar_url text, created_at timestamptz default now());
create table public.carbon_entries (id uuid primary key default gen_random_uuid(), user_id uuid references auth.users(id) on delete cascade not null, category text not null check(category in ('transport','electricity','food','shopping','waste')), activity_type text not null, value numeric not null check(value>0), unit text not null, co2_amount numeric not null, entry_date date not null, note text check(char_length(note)<=300), created_at timestamptz default now());
create table public.eco_actions (id uuid primary key default gen_random_uuid(), user_id uuid references auth.users(id) on delete cascade not null, title text not null, description text, category text, estimated_saving numeric default 0, difficulty text check(difficulty in ('Easy','Medium','Hard')), completed boolean default false, completed_at timestamptz, created_at timestamptz default now());
create table public.goals (id uuid primary key default gen_random_uuid(), user_id uuid references auth.users(id) on delete cascade not null, title text not null, category text, target_reduction numeric not null check(target_reduction>0), current_progress numeric default 0, deadline date not null, status text default 'active' check(status in ('active','completed','expired')), created_at timestamptz default now());
create table public.badges (id uuid primary key default gen_random_uuid(), user_id uuid references auth.users(id) on delete cascade not null, badge_name text not null, badge_description text, unlocked_at timestamptz default now(), unique(user_id,badge_name));
create table public.user_stats (id uuid primary key default gen_random_uuid(), user_id uuid unique references auth.users(id) on delete cascade not null, total_co2_saved numeric default 0, current_streak int default 0, longest_streak int default 0, eco_score int default 100 check(eco_score between 0 and 100), last_activity_date date, updated_at timestamptz default now());
create index carbon_entries_user_idx on public.carbon_entries(user_id);create index carbon_entries_date_idx on public.carbon_entries(entry_date);create index eco_actions_user_idx on public.eco_actions(user_id);create index goals_user_idx on public.goals(user_id);create index badges_user_idx on public.badges(user_id);
alter table public.profiles enable row level security;alter table public.carbon_entries enable row level security;alter table public.eco_actions enable row level security;alter table public.goals enable row level security;alter table public.badges enable row level security;alter table public.user_stats enable row level security;
create policy "own profile select" on public.profiles for select using(auth.uid()=id);create policy "own profile update" on public.profiles for update using(auth.uid()=id) with check(auth.uid()=id);create policy "own profile insert" on public.profiles for insert with check(auth.uid()=id);
create policy "own entries" on public.carbon_entries for all using(auth.uid()=user_id) with check(auth.uid()=user_id);create policy "own actions" on public.eco_actions for all using(auth.uid()=user_id) with check(auth.uid()=user_id);create policy "own goals" on public.goals for all using(auth.uid()=user_id) with check(auth.uid()=user_id);create policy "own badges" on public.badges for all using(auth.uid()=user_id) with check(auth.uid()=user_id);create policy "own stats" on public.user_stats for all using(auth.uid()=user_id) with check(auth.uid()=user_id);
create or replace function public.handle_new_user() returns trigger language plpgsql security definer set search_path=public as $$ begin insert into public.profiles(id,full_name,email) values(new.id,new.raw_user_meta_data->>'full_name',new.email);insert into public.user_stats(user_id) values(new.id);return new;end;$$;
create trigger on_auth_user_created after insert on auth.users for each row execute procedure public.handle_new_user();
